import UIKit

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?
    
    func application(_ application: UIApplication,
                     didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        window = UIWindow(frame: UIScreen.main.bounds)
        let mainVC = MainViewController()
        let navigationController = UINavigationController(rootViewController: mainVC)
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        return true
    }
    
    // Handle universal links
    func application(_ application: UIApplication, continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let incomingURL = userActivity.webpageURL else {
            return false
        }
        
        // Check that the URL path matches our reset password endpoint
        if incomingURL.path.lowercased() == "/reset-password" {
            // Parse query items for token
            if let token = URLComponents(url: incomingURL, resolvingAgainstBaseURL: false)?
                            .queryItems?
                            .first(where: { $0.name.lowercased() == "token" })?.value {
                navigateToPasswordReset(with: token)
                return true
            }
        }
        return false
    }
    
    private func navigateToPasswordReset(with token: String) {
        // Ensure that the navigation controller is available
        guard let navController = window?.rootViewController as? UINavigationController else { return }
        
        // Instantiate the PasswordResetViewController with the provided token
        let passwordResetVC = PasswordResetViewController(token: token)
        
        // Navigate to the password reset screen
        DispatchQueue.main.async {
            navController.pushViewController(passwordResetVC, animated: true)
        }
    }
}

